chapters.teach:
```csharp
static int Moyenne(int[] t) {
    int s = 0;
    foreach (int x in t) { s += x; }
    return s / t.Length;
}
```

chapters.starterCode:
class Program {
    // static int Moyenne(...) { ... }
    static void Main() {
        int[] t = {12, 18, 12};
        // WriteLine Moyenne(t)
    }
}

chapters.correction:
class Program {
    static int Moyenne(int[] t) {
        int s = 0;
        foreach (int x in t) { s += x; }
        return s / t.Length;
    }
    static void Main() {
        int[] t = {12, 18, 12};
        System.Console.WriteLine(Moyenne(t));
    }
}
